import type { ReactNode } from "react"
import { FocusScope } from "@gridland/utils"
import { textStyle } from "./text-style"
import { useTheme } from "./theme"
import { useKeyboardContext } from "./provider"

export interface ModalProps {
  /** The content rendered inside the modal border. */
  children: ReactNode
  /** Optional title displayed at the top inside the border. Rendered bold in the borderColor. */
  title?: string
  /** Color of the border and the title text. */
  borderColor?: string
  /**
   * The character set used for drawing the border.
   * Maps to opentui border styles: "single" | "double" | "rounded" | "heavy".
   */
  borderStyle?: "single" | "double" | "rounded" | "heavy"
  /** Callback invoked when the Escape key is pressed. */
  onClose?: () => void
  /** Keyboard handler — pass useKeyboard from @opentui/react */
  useKeyboard?: (handler: (event: any) => void) => void
}

export function Modal({
  children,
  title,
  borderColor,
  borderStyle = "rounded",
  onClose,
  useKeyboard: useKeyboardProp,
}: ModalProps) {
  const theme = useTheme()
  const useKeyboard = useKeyboardContext(useKeyboardProp)
  const resolvedBorderColor = borderColor ?? theme.muted

  // Handle Escape key
  useKeyboard?.((event: any) => {
    if (event.name === "escape" && onClose) {
      onClose()
    }
  })

  return (
    <FocusScope trap autoFocus restoreOnUnmount>
      <box flexDirection="column" flexGrow={1}>
        <box
          flexDirection="column"
          flexGrow={1}
          border
          borderStyle={borderStyle}
          borderColor={resolvedBorderColor}
        >
          {title ? (
            <>
              <box paddingX={1} marginBottom={1}>
                <text style={textStyle({ bold: true, fg: theme.primary })}>{title}</text>
              </box>
              {children}
            </>
          ) : (
            children
          )}
        </box>
      </box>
    </FocusScope>
  )
}

import { useReducer, useMemo, useRef } from "react"
import { textStyle } from "./text-style"
import { useTheme } from "./theme"
import { useKeyboardContext } from "./provider"

export type MultiSelectItem<V> = {
  key?: string
  label: string
  value: V
  group?: string
  disabled?: boolean
}

export interface MultiSelectProps<V> {
  items?: MultiSelectItem<V>[]
  defaultSelected?: V[]
  selected?: V[]
  onChange?: (values: V[]) => void
  disabled?: boolean
  invalid?: boolean
  required?: boolean
  placeholder?: string
  maxCount?: number
  title?: string
  submittedStatus?: string
  limit?: number
  enableSelectAll?: boolean
  enableClear?: boolean
  highlightColor?: string
  checkboxColor?: string
  allowEmpty?: boolean
  onSubmit?: (values: V[]) => void
  useKeyboard?: (handler: (event: any) => void) => void
}

type State<V> = {
  cursor: number
  selected: Set<V>
  submitted: boolean
}

type Action<V> =
  | { type: "MOVE"; direction: 1 | -1; max: number }
  | { type: "SET_SELECTED"; values: V[] }
  | { type: "SUBMIT" }

function reducer<V>(state: State<V>, action: Action<V>): State<V> {
  switch (action.type) {
    case "MOVE": {
      let next = state.cursor + action.direction
      if (next < 0) next = action.max - 1
      if (next >= action.max) next = 0
      return { ...state, cursor: next }
    }
    case "SET_SELECTED":
      return { ...state, selected: new Set(action.values) }
    case "SUBMIT":
      return { ...state, submitted: true }
    default:
      return state
  }
}

const VISIBLE = 12
const BAR = "│"
const CHECKED = "●"
const UNCHECKED = "○"
const CURSOR = "▸"
const SEPARATOR = "─"

type Row<V> =
  | { type: "group"; label: string }
  | { type: "separator" }
  | { type: "item"; item: MultiSelectItem<V>; index: number }

export function MultiSelect<V>({
  items = [],
  defaultSelected = [],
  selected: controlledSelected,
  onChange,
  disabled = false,
  invalid = false,
  required = false,
  placeholder,
  maxCount,
  title = "Select",
  submittedStatus = "submitted",
  limit,
  enableSelectAll = true,
  enableClear = true,
  highlightColor,
  checkboxColor,
  allowEmpty = false,
  onSubmit,
  useKeyboard: useKeyboardProp,
}: MultiSelectProps<V>) {
  const theme = useTheme()
  const useKeyboard = useKeyboardContext(useKeyboardProp)
  const resolvedHighlight = highlightColor ?? theme.primary
  const resolvedCheckbox = checkboxColor ?? theme.accent

  const isControlled = controlledSelected !== undefined
  const controlledRef = useRef(isControlled)
  if (controlledRef.current !== isControlled) {
    console.warn("MultiSelect: switching between controlled and uncontrolled is not supported.")
  }

  const [state, dispatch] = useReducer(reducer<V>, {
    cursor: 0,
    selected: new Set(isControlled ? controlledSelected : defaultSelected),
    submitted: false,
  })

  const cursorRef = useRef(0)
  const currentSelected = isControlled ? new Set(controlledSelected) : state.selected

  const { flatRows, selectableItems } = useMemo(() => {
    const rows: Row<V>[] = []
    const selectable: Array<{ item: MultiSelectItem<V>; index: number }> = []
    let index = 0
    const grouped = new Map<string, MultiSelectItem<V>[]>()
    for (const item of items) {
      const group = item.group ?? ""
      const list = grouped.get(group) ?? []
      list.push(item)
      grouped.set(group, list)
    }
    let first = true
    for (const [group, groupItems] of grouped) {
      if (!first) rows.push({ type: "separator" })
      first = false
      if (group) {
        rows.push({ type: "group", label: group })
      }
      for (const item of groupItems) {
        rows.push({ type: "item", item, index })
        selectable.push({ item, index })
        index++
      }
    }
    return { flatRows: rows, selectableItems: selectable }
  }, [items])

  const hasSubmitRow = allowEmpty || currentSelected.size > 0
  const totalPositions = selectableItems.length + (hasSubmitRow ? 1 : 0)
  const isOnSubmit = hasSubmitRow && state.cursor === selectableItems.length

  const visibleCount = limit ?? VISIBLE
  const cursorRowIndex = flatRows.findIndex((r) => r.type === "item" && r.index === state.cursor)
  const scrollOffset = Math.max(0, Math.min(cursorRowIndex - Math.floor(visibleCount / 2), flatRows.length - visibleCount))
  const visibleRows = flatRows.slice(scrollOffset, scrollOffset + visibleCount)

  const setSelected = (values: V[]) => {
    if (isControlled) {
      onChange?.(values)
    } else {
      dispatch({ type: "SET_SELECTED", values })
    }
  }

  const diamondColor = invalid ? theme.error
    : disabled ? theme.muted
    : theme.accent

  useKeyboard?.((event: any) => {
    if (state.submitted || disabled) return

    const move = (direction: 1 | -1) => {
      let next = cursorRef.current + direction
      if (next < 0) next = totalPositions - 1
      if (next >= totalPositions) next = 0
      cursorRef.current = next
      dispatch({ type: "MOVE", direction, max: totalPositions })
    }

    if (event.name === "up" || event.name === "k") {
      move(-1)
      event.preventDefault?.()
    } else if (event.name === "down" || event.name === "j") {
      move(1)
      event.preventDefault?.()
    } else if (event.name === "return") {
      const onSubmitRow = hasSubmitRow && cursorRef.current === selectableItems.length
      if (onSubmitRow) {
        dispatch({ type: "SUBMIT" })
        onSubmit?.(Array.from(currentSelected))
      } else {
        const current = selectableItems[cursorRef.current]
        if (current && !current.item.disabled) {
          const isDeselecting = currentSelected.has(current.item.value)
          if (!isDeselecting && maxCount !== undefined && currentSelected.size >= maxCount) return
          const next = new Set(currentSelected)
          if (isDeselecting) next.delete(current.item.value)
          else next.add(current.item.value)
          setSelected(Array.from(next))
        }
      }
      event.preventDefault?.()
    } else if (event.name === "a" && enableSelectAll) {
      const enabledValues = items.filter((i) => !i.disabled).map((i) => i.value)
      setSelected(maxCount !== undefined ? enabledValues.slice(0, maxCount) : enabledValues)
      event.preventDefault?.()
    } else if (event.name === "x" && enableClear) {
      setSelected([])
      event.preventDefault?.()
    }
  })

  if (state.submitted) {
    const selectedItems = items.filter((i) => currentSelected.has(i.value))
    return (
      <box flexDirection="column">
        <text>
          <span style={textStyle({ fg: theme.success })}>{"◆ "}</span>
          <span style={textStyle({ bold: true, fg: theme.foreground })}>{title}</span>
        </text>
        {selectedItems.map((item) => (
          <text key={item.key ?? String(item.value)}>
            <span style={textStyle({ fg: theme.success })}>{BAR} </span>
            <span>{"  "}</span>
            <span style={textStyle({ fg: theme.success })}>{CHECKED} </span>
            <span style={textStyle({ fg: theme.foreground })}>{item.label}</span>
          </text>
        ))}
        <text> </text>
        <text>
          <span style={textStyle({ dim: true, fg: theme.muted })}>{selectedItems.length} selected — {submittedStatus}</span>
        </text>
      </box>
    )
  }

  const hasItems = selectableItems.length > 0

  return (
    <box flexDirection="column">
      <text>
        <span style={textStyle({ fg: diamondColor, dim: disabled })}>{"◆ "}</span>
        <span style={textStyle({ bold: true, dim: disabled, fg: theme.foreground })}>{title}</span>
        {required && <span style={textStyle({ fg: theme.error })}>{" *"}</span>}
        {maxCount !== undefined && (
          <span style={textStyle({ dim: true, fg: theme.muted })}>{` (${currentSelected.size}/${maxCount})`}</span>
        )}
      </text>
      {invalid && (
        <text>
          <span style={textStyle({ fg: theme.muted })}>{BAR} </span>
          <span style={textStyle({ fg: theme.error })}>{"  Please select at least one option"}</span>
        </text>
      )}
      {!hasItems && placeholder && (
        <text>
          <span style={textStyle({ fg: theme.muted })}>{BAR} </span>
          <span style={textStyle({ dim: true, fg: theme.muted })}>{"  "}{placeholder}</span>
        </text>
      )}
      {visibleRows.map((row, i) => {
        if (row.type === "separator") {
          return (
            <text key={`sep-${i}`}>
              <span style={textStyle({ fg: theme.muted })}>{BAR} </span>
              <span style={textStyle({ fg: theme.muted })}>{"  "}{SEPARATOR.repeat(20)}</span>
            </text>
          )
        }

        if (row.type === "group") {
          return (
            <text key={`group-${row.label}`}>
              <span style={textStyle({ fg: theme.muted })}>{BAR} </span>
              <span style={textStyle({ bold: true, fg: theme.muted })}>{` ${row.label}`}</span>
            </text>
          )
        }

        const { item, index: itemIndex } = row
        const isHighlighted = !disabled && itemIndex === state.cursor
        const isSelected = currentSelected.has(item.value)
        const isItemDisabled = disabled || !!item.disabled
        const itemColor = isItemDisabled ? theme.muted
          : isHighlighted ? resolvedHighlight
          : isSelected ? resolvedCheckbox
          : theme.foreground

        return (
          <text key={item.key ?? String(item.value)}>
            <span style={textStyle({ fg: theme.muted })}>{BAR} </span>
            <span style={textStyle({ fg: isHighlighted ? resolvedHighlight : undefined })}>
              {isHighlighted ? CURSOR : " "}{" "}
            </span>
            <span style={textStyle({ fg: isSelected && !isItemDisabled ? resolvedCheckbox : theme.muted, dim: isItemDisabled })}>
              {isSelected ? CHECKED : UNCHECKED}{" "}
            </span>
            <span style={textStyle({ fg: itemColor, dim: isItemDisabled })}>
              {item.label}
            </span>
          </text>
        )
      })}
      {hasSubmitRow && (
        <text>
          <span style={textStyle({ fg: theme.muted })}>{BAR} </span>
          <span style={textStyle({ fg: isOnSubmit ? resolvedHighlight : undefined })}>
            {isOnSubmit ? CURSOR : " "}{" "}
          </span>
          <span style={textStyle({ fg: isOnSubmit ? resolvedHighlight : theme.muted })}>
            {"↳ "}
          </span>
          <span style={textStyle({ fg: isOnSubmit ? resolvedHighlight : theme.foreground })}>
            {"Submit"}
          </span>
        </text>
      )}
    </box>
  )
}

// @ts-nocheck — OpenTUI intrinsic elements conflict with React's HTML/SVG types
import {
  useState,
  useRef,
  useCallback,
  useEffect,
  useMemo,
  createContext,
  useContext,
  type ReactNode,
  type PropsWithChildren,
} from "react"
import { textStyle } from "./text-style"
import { useTheme } from "./theme"
import { useKeyboardContext } from "./provider"
import { useRegistryCommands } from "./command-registry"
export type { PromptInputCommand } from "./command-registry"

/** Chat lifecycle status. Compatible with any AI SDK. */
export type ChatStatus = "ready" | "submitted" | "streaming" | "error"

export interface Suggestion {
  text: string
  desc?: string
}

/** Message shape passed to onSubmit. */
export interface PromptInputMessage {
  text: string
}

// ============================================================================
// Provider (lifted state)
// ============================================================================

export interface TextInputContext {
  value: string
  setValue: (v: string) => void
  clear: () => void
}

export interface SuggestionsContext {
  suggestions: Suggestion[]
  selectedIndex: number
  setSuggestions: (s: Suggestion[]) => void
  setSelectedIndex: (i: number) => void
  clear: () => void
}

interface PromptInputControllerProps {
  textInput: TextInputContext
  suggestions: SuggestionsContext
}

const PromptInputControllerCtx = createContext<PromptInputControllerProps | null>(null)

/** Access lifted PromptInput state from outside the component. Requires `<PromptInputProvider>`. */
export function usePromptInputController(): PromptInputControllerProps {
  const ctx = useContext(PromptInputControllerCtx)
  if (!ctx) {
    throw new Error("Wrap your component inside <PromptInputProvider> to use usePromptInputController().")
  }
  return ctx
}

const useOptionalController = () => useContext(PromptInputControllerCtx)

export type PromptInputProviderProps = PropsWithChildren<{
  initialInput?: string
}>

/**
 * Optional provider that lifts PromptInput state outside of PromptInput.
 * Without it, PromptInput stays fully self-managed.
 */
export function PromptInputProvider({ initialInput = "", children }: PromptInputProviderProps) {
  const [value, setValueState] = useState(initialInput)
  const clearInput = useCallback(() => setValueState(""), [])

  const [suggestions, setSuggestions] = useState<Suggestion[]>([])
  const [selectedIndex, setSelectedIndex] = useState(0)
  const clearSuggestions = useCallback(() => {
    setSuggestions([])
    setSelectedIndex(0)
  }, [])

  const controller = useMemo<PromptInputControllerProps>(
    () => ({
      textInput: { value, setValue: setValueState, clear: clearInput },
      suggestions: {
        suggestions,
        selectedIndex,
        setSuggestions,
        setSelectedIndex,
        clear: clearSuggestions,
      },
    }),
    [value, clearInput, suggestions, selectedIndex, clearSuggestions],
  )

  return (
    <PromptInputControllerCtx.Provider value={controller}>
      {children}
    </PromptInputControllerCtx.Provider>
  )
}

// ============================================================================
// Component Context (rendering state for subcomponents)
// ============================================================================

export interface PromptInputContextValue {
  value: string
  isFocused: boolean
  disabled: boolean
  status?: ChatStatus
  onStop?: () => void
  statusHintText: string
  placeholder: string
  prompt: string
  promptColor: string
  suggestions: Suggestion[]
  sugIdx: number
  maxSuggestions: number
  errorText: string
  model?: string
  dividerColor?: string
  dividerDashed?: boolean
  theme: ReturnType<typeof useTheme>
  handleInput: (value: string) => void
  handleInputSubmit: (value: string) => void
  handleInputKeyDown: (key: any) => void
}

const PromptInputContext = createContext<PromptInputContextValue | null>(null)

/** Hook for accessing PromptInput state from compound subcomponents. */
export function usePromptInput(): PromptInputContextValue {
  const ctx = useContext(PromptInputContext)
  if (!ctx) {
    throw new Error("usePromptInput must be used within a <PromptInput> component")
  }
  return ctx
}

// ============================================================================
// Props
// ============================================================================

export interface PromptInputProps {
  /** Controlled input value */
  value?: string
  /** Default value for uncontrolled mode */
  defaultValue?: string
  /**
   * Called when user submits a message.
   * Receives `{ text }`. Compatible with Vercel AI SDK's `sendMessage` and
   * easily mapped to any other SDK. If the handler returns a Promise, input
   * is cleared on resolve and preserved on reject so the user can retry.
   */
  onSubmit?: (message: PromptInputMessage) => void | Promise<void>
  /** Callback when input value changes */
  onChange?: (text: string) => void
  /** Placeholder text when input is empty */
  placeholder?: string
  /** Prompt character shown before input */
  prompt?: string
  /** Color of the prompt character */
  promptColor?: string
  /**
   * AI chat status — drives disabled state and status indicator.
   * When provided, takes precedence over `disabled`/`disabledText`.
   */
  status?: ChatStatus
  /** Called when user presses Escape during streaming to stop generation */
  onStop?: () => void
  /** Text shown when status is "submitted" */
  submittedText?: string
  /** Text shown when status is "streaming" */
  streamingText?: string
  /** Text shown when status is "error" */
  errorText?: string
  /** Disable input. Ignored when `status` is provided. */
  disabled?: boolean
  /** Text shown when disabled. Ignored when `status` is provided. */
  disabledText?: string
  /** Slash commands for autocomplete. Commands with `onExecute` are handled internally. */
  commands?: PromptInputCommand[]
  /** Dynamically-provided skills (e.g. from Claude Code). Merged into autocomplete alongside commands. */
  skills?: PromptInputCommand[]
  /** File paths for @ mention autocomplete */
  files?: string[]
  /** Custom suggestion provider — overrides commands/files */
  getSuggestions?: (value: string) => Suggestion[]
  /** Max visible suggestions */
  maxSuggestions?: number
  /** Enable command history with up/down arrows */
  enableHistory?: boolean
  /** Model name displayed below the input */
  model?: string
  /** Whether the input is focused and accepting keystrokes */
  focus?: boolean
  /** Show horizontal dividers above and below the input */
  showDividers?: boolean
  /** Auto-focus the input on mount (ensures canvas has keyboard focus in the browser) */
  autoFocus?: boolean
  /** Override divider line color (e.g. for focus indicators) */
  dividerColor?: string
  /** Use dashed divider lines (╌) instead of solid (─) */
  dividerDashed?: boolean
  /** Keyboard hook from @opentui/react */
  useKeyboard?: (handler: (event: any) => void) => void
  /** Compound mode: provide subcomponents as children */
  children?: ReactNode
}

// ============================================================================
// Helpers
// ============================================================================

function computeDefaultSuggestions(
  input: string,
  commands: PromptInputCommand[],
  files: string[],
): Suggestion[] {
  if (input.startsWith("/") && commands.length > 0) {
    return commands
      .filter((c) => !c.hidden && c.cmd.startsWith(input))
      .map((c) => ({ text: c.cmd, desc: c.desc }))
  }
  if (input.includes("@") && files.length > 0) {
    const query = input.split("@").pop() ?? ""
    return files
      .filter((f) => f.toLowerCase().includes(query.toLowerCase()))
      .map((f) => ({ text: "@" + f }))
  }
  return []
}

function resolveStatusHintText(
  status: ChatStatus | undefined,
  submittedText: string,
  streamingText: string,
  errorText: string,
  disabledText: string,
): string {
  if (status === "submitted") return submittedText
  if (status === "streaming") return streamingText
  if (status === "error") return errorText
  return disabledText
}

// ============================================================================
// Subcomponents
// ============================================================================

/** Horizontal divider line that extends into parent border gutters. */
function PromptInputDivider() {
  const { dividerColor, dividerDashed, theme } = usePromptInput()
  const color = dividerColor ?? theme.muted
  const char = dividerDashed ? "╌" : "─"
  return (
    <text wrapMode="none" marginLeft={-1} marginRight={-1}>
      <span style={textStyle({ dim: !dividerColor, fg: color })}>{char.repeat(500)}</span>
    </text>
  )
}

/** Autocomplete suggestion list. */
function PromptInputSuggestions() {
  const { suggestions, sugIdx, maxSuggestions, theme } = usePromptInput()
  const visible = suggestions.slice(0, maxSuggestions)
  if (visible.length === 0) return null
  return (
    <box flexDirection="column" marginLeft={2}>
      {visible.map((sug, i) => {
        const active = i === sugIdx
        return (
          <text key={sug.text}>
            <span style={textStyle({ fg: active ? theme.primary : theme.muted })}>
              {active ? "▸ " : "  "}
            </span>
            <span style={textStyle({ fg: active ? theme.primary : theme.muted, bold: active })}>
              {sug.text}
            </span>
            {sug.desc && (
              <span style={textStyle({ dim: true, fg: theme.placeholder })}>{" " + sug.desc}</span>
            )}
          </text>
        )
      })}
    </box>
  )
}

/** Prompt char + input element when focused, static text otherwise. */
function PromptInputTextarea() {
  const { value, isFocused, disabled, statusHintText, placeholder, prompt, promptColor, theme, handleInput, handleInputSubmit, handleInputKeyDown } = usePromptInput()
  return (
    <box flexDirection="row">
      <text><span style={textStyle({ fg: promptColor })}>{prompt}</span></text>
      {isFocused ? (
        <input
          value={value}
          placeholder={placeholder}
          focused
          onInput={handleInput}
          onSubmit={handleInputSubmit}
          onKeyDown={handleInputKeyDown}
          cursorColor={theme.muted}
          cursorStyle={{ style: "line", blinking: !value }}
          placeholderColor={theme.placeholder}
          textColor={theme.foreground}
        />
      ) : disabled && value.length === 0 ? (
        <text><span style={textStyle({ dim: true, fg: theme.placeholder })}>{statusHintText}</span></text>
      ) : (
        <text><span style={textStyle({ fg: value ? theme.foreground : theme.placeholder, dim: !value })}>{value || placeholder}</span></text>
      )}
    </box>
  )
}

/**
 * Status indicator: ⏎ ready, ◐ submitted, ■ streaming, ✕ error.
 * When `status` and `onStop` are provided via context, the streaming icon
 * doubles as a stop button (Escape triggers onStop).
 */
function PromptInputSubmit(props: { status?: ChatStatus; onStop?: () => void }) {
  const ctx = usePromptInput()
  const status = props.status ?? ctx.status
  const onStop = props.onStop ?? ctx.onStop
  const { disabled, theme } = ctx

  const isGenerating = status === "submitted" || status === "streaming"

  const icon =
    status === "submitted" ? "◐"
    : status === "streaming" ? (onStop ? "■" : "◐")
    : status === "error" ? "✕"
    : "⏎"

  const color =
    status === "error" ? theme.error
    : isGenerating ? theme.muted
    : disabled ? theme.muted
    : theme.primary

  return (
    <text>
      <span style={textStyle({ fg: color })}>{" " + icon}</span>
    </text>
  )
}

/** Error/hint text below input. */
function PromptInputStatusText() {
  const { status, errorText, theme } = usePromptInput()
  if (status !== "error") return null
  return (
    <text>
      <span style={textStyle({ fg: theme.error })}>{errorText}</span>
    </text>
  )
}

/** Model label shown below the input. */
function PromptInputModel() {
  const { model, theme } = usePromptInput()
  if (!model) return null
  return (
    <text dim color={theme.muted}>model: {model}</text>
  )
}

// ============================================================================
// Root component
// ============================================================================

export function PromptInput({
  value: controlledValue,
  defaultValue = "",
  onSubmit,
  onChange,
  placeholder = "Type a message...",
  prompt = "❯ ",
  promptColor,
  status,
  onStop,
  submittedText = "Thinking...",
  streamingText: streamingLabel = "Generating...",
  errorText = "An error occurred. Try again.",
  disabled: disabledProp = false,
  disabledText = "Generating...",
  commands = [],
  skills = [],
  files = [],
  getSuggestions: customGetSuggestions,
  maxSuggestions = 5,
  enableHistory = true,
  model,
  focus = false,
  showDividers = true,
  autoFocus = false,
  dividerColor,
  dividerDashed,
  useKeyboard: useKeyboardProp,
  children,
}: PromptInputProps) {
  const theme = useTheme()
  const useKeyboard = useKeyboardContext(useKeyboardProp)

  const registryCommands = useRegistryCommands()
  const allCommands = useMemo(() => {
    const base = [...commands, ...skills]
    if (registryCommands.length === 0) return base
    const propCmds = new Set(base.map(c => c.cmd))
    const deduped = registryCommands.filter(c => !propCmds.has(c.cmd))
    return [...base, ...deduped]
  }, [commands, skills, registryCommands])

  // Auto-focus: ensure the canvas has DOM focus so keyboard events reach useKeyboard
  useEffect(() => {
    if (!autoFocus) return
    if (typeof document === "undefined") return
    const canvas = document.querySelector("canvas")
    if (canvas && document.activeElement !== canvas) {
      canvas.focus()
    }
  }, [autoFocus])
  const resolvedPromptColor = promptColor ?? theme.muted

  // Status-driven state
  const disabled = status ? status === "submitted" || status === "streaming" : disabledProp
  const isFocused = focus && !disabled
  const statusHintText = resolveStatusHintText(status, submittedText, streamingLabel, errorText, disabledText)

  // ── Dual-mode state: provider-managed or self-managed ──────────────────
  const controller = useOptionalController()
  const usingProvider = !!controller

  const isControlled = controlledValue !== undefined
  const controlledRef = useRef(isControlled)
  if (controlledRef.current !== isControlled) {
    console.warn("PromptInput: switching between controlled and uncontrolled is not supported.")
  }

  // Local state (used when no provider and not controlled)
  const [localValue, setLocalValue] = useState(defaultValue)
  const [localSuggestions, setLocalSuggestions] = useState<Suggestion[]>([])
  const [localSugIdx, setLocalSugIdx] = useState(0)
  const [history, setHistory] = useState<string[]>([])
  const [histIdx, setHistIdx] = useState(-1)

  // Resolve value from: controlled prop > provider > local
  const value = isControlled
    ? controlledValue
    : usingProvider
      ? controller.textInput.value
      : localValue

  const suggestions = usingProvider ? controller.suggestions.suggestions : localSuggestions
  const sugIdx = usingProvider ? controller.suggestions.selectedIndex : localSugIdx

  // ── State updaters (unified across modes) ──────────────────────────────

  const valueRef = useRef(defaultValue)
  if (isControlled) valueRef.current = controlledValue
  else if (usingProvider) valueRef.current = controller.textInput.value
  else valueRef.current = localValue

  const suggestionsRef = useRef<Suggestion[]>([])
  suggestionsRef.current = suggestions
  const sugIdxRef = useRef(0)
  sugIdxRef.current = sugIdx
  const historyRef = useRef<string[]>([])
  historyRef.current = history
  const histIdxRef = useRef(-1)
  histIdxRef.current = histIdx

  const setSug = useCallback((next: Suggestion[]) => {
    suggestionsRef.current = next
    if (usingProvider) {
      controller.suggestions.setSuggestions(next)
    } else {
      setLocalSuggestions(next)
    }
  }, [usingProvider, controller])

  const setSugI = useCallback((next: number) => {
    sugIdxRef.current = next
    if (usingProvider) {
      controller.suggestions.setSelectedIndex(next)
    } else {
      setLocalSugIdx(next)
    }
  }, [usingProvider, controller])

  const setHist = useCallback((next: string[]) => {
    historyRef.current = next
    setHistory(next)
  }, [])

  const setHistI = useCallback((next: number) => {
    histIdxRef.current = next
    setHistIdx(next)
  }, [])

  const computeSuggestions = useCallback((input: string): Suggestion[] => {
    if (customGetSuggestions) return customGetSuggestions(input)
    return computeDefaultSuggestions(input, allCommands, files)
  }, [customGetSuggestions, allCommands, files])

  const updateValue = useCallback((next: string) => {
    valueRef.current = next
    if (isControlled) {
      // controlled: only fire onChange, parent owns state
    } else if (usingProvider) {
      controller.textInput.setValue(next)
    } else {
      setLocalValue(next)
    }
    onChange?.(next)
    const sug = computeSuggestions(next)
    setSug(sug)
    setSugI(0)
  }, [isControlled, usingProvider, controller, onChange, computeSuggestions, setSug, setSugI])

  // ── Submit handler (auto-clears on success, preserves on error) ────────

  const clearInput = useCallback(() => {
    if (usingProvider) {
      controller.textInput.clear()
    } else if (!isControlled) {
      setLocalValue("")
    }
    onChange?.("")
  }, [usingProvider, controller, isControlled, onChange])

  const handleSubmit = useCallback((text: string) => {
    const matched = allCommands.find((c) => c.cmd === text)
    if (matched?.onExecute) {
      matched.onExecute()
      clearInput()
      return
    }

    if (!onSubmit) return

    const result = onSubmit({ text })

    // Handle async onSubmit: clear on resolve, preserve on reject
    if (result instanceof Promise) {
      result.then(
        () => clearInput(),
        () => { /* Don't clear on error — user may want to retry */ },
      )
    } else {
      // Sync onSubmit completed without throwing — clear
      clearInput()
    }
  }, [onSubmit, clearInput, allCommands])

  // ── Input handlers (passed to <input> intrinsic via context) ───────────

  const handleInputSubmit = (text: string) => {
    const trimmed = text.trim()
    if (!trimmed) return
    if (enableHistory) {
      setHist([trimmed, ...historyRef.current])
    }
    updateValue("")
    setHistI(-1)
    handleSubmit(trimmed)
  }

  const handleInputKeyDown = (key: any) => {
    // Return with active suggestions: custom submit logic
    if (key.name === "return" && suggestionsRef.current.length > 0) {
      const sel = suggestionsRef.current[sugIdxRef.current]
      if (sel) {
        if (valueRef.current.startsWith("/")) {
          // Slash commands: submit immediately on selection
          updateValue("")
          if (enableHistory) {
            setHist([sel.text, ...historyRef.current])
          }
          setHistI(-1)
          handleSubmit(sel.text)
        } else {
          const base = valueRef.current.slice(0, valueRef.current.lastIndexOf("@"))
          updateValue(base + sel.text + " ")
          setSug([])
        }
      }
      key.preventDefault()
      return
    }

    // Tab: cycle suggestions
    if (key.name === "tab" && suggestionsRef.current.length > 0) {
      setSugI((sugIdxRef.current + 1) % suggestionsRef.current.length)
      key.preventDefault()
      return
    }

    // Up: navigate suggestions or history
    if (key.name === "up") {
      if (suggestionsRef.current.length > 0) {
        setSugI(Math.max(0, sugIdxRef.current - 1))
      } else if (enableHistory && historyRef.current.length > 0) {
        const idx = Math.min(historyRef.current.length - 1, histIdxRef.current + 1)
        setHistI(idx)
        updateValue(historyRef.current[idx]!)
      }
      key.preventDefault()
      return
    }

    // Down: navigate suggestions or history
    if (key.name === "down") {
      if (suggestionsRef.current.length > 0) {
        setSugI(Math.min(suggestionsRef.current.length - 1, sugIdxRef.current + 1))
      } else if (enableHistory && histIdxRef.current > 0) {
        const nextIdx = histIdxRef.current - 1
        setHistI(nextIdx)
        updateValue(historyRef.current[nextIdx]!)
      } else if (enableHistory && histIdxRef.current === 0) {
        setHistI(-1)
        updateValue("")
      }
      key.preventDefault()
      return
    }

    // Escape: dismiss suggestions
    if (key.name === "escape") {
      if (suggestionsRef.current.length > 0) {
        setSug([])
        key.preventDefault()
      }
      return
    }
  }

  // ── Keyboard handler ───────────────────────────────────────────────────
  // When focused, <input> handles text input; useKeyboard only handles Escape→onStop.
  // When not focused (no <input> rendered), useKeyboard provides full keyboard fallback
  // for character input, suggestions, and history (used in tests and unfocused state).

  useKeyboard?.((event: any) => {
    // Escape during submitted/streaming calls onStop (always active)
    if (event.name === "escape" && (status === "streaming" || status === "submitted") && onStop) {
      onStop()
      return
    }

    // When <input> is rendered, it handles everything else
    if (isFocused) return

    if (disabled) return

    if (event.name === "return") {
      if (suggestionsRef.current.length > 0) {
        const sel = suggestionsRef.current[sugIdxRef.current]
        if (sel) {
          if (valueRef.current.startsWith("/")) {
            updateValue("")
            if (enableHistory) {
              setHist([sel.text, ...historyRef.current])
            }
            setHistI(-1)
            handleSubmit(sel.text)
          } else {
            const base = valueRef.current.slice(0, valueRef.current.lastIndexOf("@"))
            updateValue(base + sel.text + " ")
            setSug([])
          }
        }
      } else {
        const trimmed = valueRef.current.trim()
        if (!trimmed) return
        if (enableHistory) {
          setHist([trimmed, ...historyRef.current])
        }
        updateValue("")
        setHistI(-1)
        handleSubmit(trimmed)
      }
      return
    }

    if (event.name === "tab" && suggestionsRef.current.length > 0) {
      setSugI((sugIdxRef.current + 1) % suggestionsRef.current.length)
      return
    }

    if (event.name === "up") {
      if (suggestionsRef.current.length > 0) {
        setSugI(Math.max(0, sugIdxRef.current - 1))
      } else if (enableHistory && historyRef.current.length > 0) {
        const idx = Math.min(historyRef.current.length - 1, histIdxRef.current + 1)
        setHistI(idx)
        updateValue(historyRef.current[idx]!)
      }
      return
    }

    if (event.name === "down") {
      if (suggestionsRef.current.length > 0) {
        setSugI(Math.min(suggestionsRef.current.length - 1, sugIdxRef.current + 1))
      } else if (enableHistory && histIdxRef.current > 0) {
        const nextIdx = histIdxRef.current - 1
        setHistI(nextIdx)
        updateValue(historyRef.current[nextIdx]!)
      } else if (enableHistory && histIdxRef.current === 0) {
        setHistI(-1)
        updateValue("")
      }
      return
    }

    if (event.name === "escape") {
      if (suggestionsRef.current.length > 0) {
        setSug([])
      }
      return
    }

    if (event.name === "backspace" || event.name === "delete") {
      updateValue(valueRef.current.slice(0, -1))
      return
    }

    if (event.ctrl || event.meta) return

    if (event.name === "space") {
      updateValue(valueRef.current + " ")
      return
    }

    if (event.name && event.name.length === 1) {
      updateValue(valueRef.current + event.name)
    }
  })

  // ── Build context for subcomponents ────────────────────────────────────

  const visibleSuggestions = suggestions.slice(0, maxSuggestions)

  const ctxValue: PromptInputContextValue = {
    value,
    isFocused,
    disabled,
    status,
    onStop,
    statusHintText,
    placeholder,
    prompt,
    promptColor: resolvedPromptColor,
    suggestions: visibleSuggestions,
    sugIdx,
    maxSuggestions,
    errorText,
    model,
    dividerColor,
    dividerDashed,
    theme,
    handleInput: updateValue,
    handleInputSubmit,
    handleInputKeyDown,
  }

  // ── Render ─────────────────────────────────────────────────────────────

  if (children) {
    return (
      <PromptInputContext.Provider value={ctxValue}>
        <box flexDirection="column" flexShrink={0}>
          {children}
        </box>
      </PromptInputContext.Provider>
    )
  }

  return (
    <PromptInputContext.Provider value={ctxValue}>
      <box flexDirection="column" flexShrink={0}>
        {showDividers && <PromptInputDivider />}
        <box flexDirection="column" paddingX={1}>
          <PromptInputSuggestions />
          <PromptInputTextarea />
          <PromptInputStatusText />
        </box>
        {showDividers && <PromptInputDivider />}
        <box paddingX={1}>
          <PromptInputModel />
        </box>
      </box>
    </PromptInputContext.Provider>
  )
}

// ── Attach subcomponents ─────────────────────────────────────────────────

PromptInput.Textarea = PromptInputTextarea
PromptInput.Suggestions = PromptInputSuggestions
PromptInput.Submit = PromptInputSubmit
PromptInput.Divider = PromptInputDivider
PromptInput.StatusText = PromptInputStatusText
PromptInput.Model = PromptInputModel

import { useReducer, useMemo, useRef } from "react"
import { textStyle } from "./text-style"
import { useTheme } from "./theme"
import { useKeyboardContext } from "./provider"

export type SelectInputItem<V> = {
  key?: string
  label: string
  value: V
  group?: string
  disabled?: boolean
}

export interface SelectInputProps<V> {
  items?: SelectInputItem<V>[]
  defaultValue?: V
  value?: V
  onChange?: (value: V) => void
  disabled?: boolean
  invalid?: boolean
  required?: boolean
  placeholder?: string
  title?: string
  submittedStatus?: string
  limit?: number
  highlightColor?: string
  onSubmit?: (value: V) => void
  useKeyboard?: (handler: (event: any) => void) => void
}

type State = {
  cursor: number
  submitted: boolean
}

type Action =
  | { type: "MOVE"; direction: 1 | -1; max: number }
  | { type: "SUBMIT" }

function reducer(state: State, action: Action): State {
  switch (action.type) {
    case "MOVE": {
      let next = state.cursor + action.direction
      if (next < 0) next = action.max - 1
      if (next >= action.max) next = 0
      return { ...state, cursor: next }
    }
    case "SUBMIT":
      return { ...state, submitted: true }
    default:
      return state
  }
}

const VISIBLE = 12
const BAR = "│"
const RADIO = "○"
const CURSOR = "▸"
const SEPARATOR = "─"

type Row<V> =
  | { type: "group"; label: string }
  | { type: "separator" }
  | { type: "item"; item: SelectInputItem<V>; index: number }

export function SelectInput<V>({
  items = [],
  defaultValue,
  value: controlledValue,
  onChange,
  disabled = false,
  invalid = false,
  required = false,
  placeholder,
  title = "Select",
  submittedStatus = "submitted",
  limit,
  highlightColor,
  onSubmit,
  useKeyboard: useKeyboardProp,
}: SelectInputProps<V>) {
  const theme = useTheme()
  const useKeyboard = useKeyboardContext(useKeyboardProp)
  const resolvedHighlight = highlightColor ?? theme.primary

  const isControlled = controlledValue !== undefined
  const controlledRef = useRef(isControlled)
  if (controlledRef.current !== isControlled) {
    console.warn("SelectInput: switching between controlled and uncontrolled is not supported.")
  }

  const initialIndex = items.findIndex((i) => i.value === (isControlled ? controlledValue : defaultValue))

  const [state, dispatch] = useReducer(reducer, {
    cursor: Math.max(0, initialIndex),
    submitted: false,
  })

  const { flatRows, selectableItems } = useMemo(() => {
    const rows: Row<V>[] = []
    const selectable: Array<{ item: SelectInputItem<V>; index: number }> = []
    let index = 0
    const grouped = new Map<string, SelectInputItem<V>[]>()
    for (const item of items) {
      const group = item.group ?? ""
      const list = grouped.get(group) ?? []
      list.push(item)
      grouped.set(group, list)
    }
    let first = true
    for (const [group, groupItems] of grouped) {
      if (!first) rows.push({ type: "separator" })
      first = false
      if (group) {
        rows.push({ type: "group", label: group })
      }
      for (const item of groupItems) {
        rows.push({ type: "item", item, index })
        selectable.push({ item, index })
        index++
      }
    }
    return { flatRows: rows, selectableItems: selectable }
  }, [items])

  const visibleCount = limit ?? VISIBLE
  const cursorRowIndex = flatRows.findIndex((r) => r.type === "item" && r.index === state.cursor)
  const scrollOffset = Math.max(0, Math.min(cursorRowIndex - Math.floor(visibleCount / 2), flatRows.length - visibleCount))
  const visibleRows = flatRows.slice(scrollOffset, scrollOffset + visibleCount)

  const diamondColor = invalid ? theme.error
    : disabled ? theme.muted
    : theme.accent

  useKeyboard?.((event: any) => {
    if (state.submitted || disabled) return

    if (event.name === "up" || event.name === "k") {
      const direction = -1
      let next = state.cursor + direction
      if (next < 0) next = selectableItems.length - 1
      dispatch({ type: "MOVE", direction, max: selectableItems.length })
      const nextItem = selectableItems[next]
      if (nextItem && !nextItem.item.disabled) {
        onChange?.(nextItem.item.value)
      }
      event.preventDefault?.()
    } else if (event.name === "down" || event.name === "j") {
      const direction = 1
      let next = state.cursor + direction
      if (next >= selectableItems.length) next = 0
      dispatch({ type: "MOVE", direction, max: selectableItems.length })
      const nextItem = selectableItems[next]
      if (nextItem && !nextItem.item.disabled) {
        onChange?.(nextItem.item.value)
      }
      event.preventDefault?.()
    } else if (event.name === "return") {
      const current = selectableItems[state.cursor]
      if (current && !current.item.disabled) {
        dispatch({ type: "SUBMIT" })
        onSubmit?.(isControlled ? controlledValue : current.item.value)
      }
      event.preventDefault?.()
    }
  })

  if (state.submitted) {
    const selectedItem = isControlled
      ? items.find((i) => i.value === controlledValue)
      : selectableItems[state.cursor]?.item
    return (
      <box flexDirection="column">
        <text>
          <span style={textStyle({ fg: theme.success })}>{"◆ "}</span>
          <span style={textStyle({ bold: true, fg: theme.foreground })}>{title}</span>
        </text>
        {selectedItem && (
          <text>
            <span style={textStyle({ fg: theme.success })}>{BAR} </span>
            <span>{"  "}</span>
            <span style={textStyle({ fg: theme.success })}>{"● "}</span>
            <span style={textStyle({ fg: theme.foreground })}>{selectedItem.label}</span>
          </text>
        )}
        <text> </text>
        <text>
          <span style={textStyle({ dim: true, fg: theme.muted })}>{submittedStatus}</span>
        </text>
      </box>
    )
  }

  const hasItems = selectableItems.length > 0

  return (
    <box flexDirection="column">
      <text>
        <span style={textStyle({ fg: diamondColor, dim: disabled })}>{"◆ "}</span>
        <span style={textStyle({ bold: true, dim: disabled, fg: theme.foreground })}>{title}</span>
        {required && <span style={textStyle({ fg: theme.error })}>{" *"}</span>}
      </text>
      {invalid && (
        <text>
          <span style={textStyle({ fg: theme.muted })}>{BAR} </span>
          <span style={textStyle({ fg: theme.error })}>{"  Please select an option"}</span>
        </text>
      )}
      {!hasItems && placeholder && (
        <text>
          <span style={textStyle({ fg: theme.muted })}>{BAR} </span>
          <span style={textStyle({ dim: true, fg: theme.muted })}>{"  "}{placeholder}</span>
        </text>
      )}
      {visibleRows.map((row, i) => {
        if (row.type === "separator") {
          return (
            <text key={`sep-${i}`}>
              <span style={textStyle({ fg: theme.muted })}>{BAR} </span>
              <span style={textStyle({ fg: theme.muted })}>{"  "}{SEPARATOR.repeat(20)}</span>
            </text>
          )
        }

        if (row.type === "group") {
          return (
            <text key={`group-${row.label}`}>
              <span style={textStyle({ fg: theme.muted })}>{BAR} </span>
              <span style={textStyle({ bold: true, fg: theme.muted })}>{` ${row.label}`}</span>
            </text>
          )
        }

        const { item, index: itemIndex } = row
        const isHighlighted = !disabled && itemIndex === state.cursor
        const isItemDisabled = disabled || !!item.disabled
        const itemColor = isItemDisabled ? theme.muted
          : isHighlighted ? resolvedHighlight
          : theme.foreground

        return (
          <text key={item.key ?? String(item.value)}>
            <span style={textStyle({ fg: theme.muted })}>{BAR} </span>
            <span style={textStyle({ fg: isHighlighted ? resolvedHighlight : undefined })}>
              {isHighlighted ? CURSOR : " "}{" "}
            </span>
            <span style={textStyle({ fg: theme.muted, dim: isItemDisabled })}>
              {RADIO}{" "}
            </span>
            <span style={textStyle({ fg: itemColor, dim: isItemDisabled })}>
              {item.label}
            </span>
          </text>
        )
      })}
    </box>
  )
}

import { useEffect, useState } from "react"
import { useTheme } from "./theme"

const VARIANTS = {
  dots: { frames: ["⠋", "⠙", "⠹", "⠸", "⠼", "⠴", "⠦", "⠧", "⠇", "⠏"], interval: 80 },
  pulse: { frames: ["·", "∙", "●", "∙", "·", "·", "·"], interval: 180 },
  meter: { frames: ["▱▱▱", "▰▱▱", "▰▰▱", "▰▰▰", "▰▰▱", "▰▱▱", "▱▱▱"], interval: 143 },
  bloom: { frames: ["·", "✦", "✧", "✹", "✺", "❋", "✸", "✵", "✸", "❋", "✺", "✹", "✧", "✦", "·", "·"], interval: 100 },
  ellipsis: { frames: ["   ", ".  ", ".. ", "..."], interval: 333 },
} as const

export type SpinnerVariant = keyof typeof VARIANTS
export type SpinnerStatus = "spinning" | "success" | "error" | "warning" | "info"

export const VARIANT_NAMES = Object.keys(VARIANTS) as SpinnerVariant[]

const STATUS_SYMBOLS: Record<Exclude<SpinnerStatus, "spinning">, string> = {
  success: "✔",
  error: "✖",
  warning: "⚠",
  info: "ℹ",
}

export interface SpinnerProps {
  variant?: SpinnerVariant
  text?: string
  color?: string
  status?: SpinnerStatus
}

export function Spinner({ variant = "dots", text, color, status = "spinning" }: SpinnerProps) {
  const theme = useTheme()
  const { frames, interval } = VARIANTS[variant]
  const [frame, setFrame] = useState(0)

  useEffect(() => {
    if (status !== "spinning") return
    setFrame(0)
    const timer = setInterval(() => {
      setFrame((prev) => (prev + 1) % frames.length)
    }, interval)
    return () => clearInterval(timer)
  }, [variant, status])

  if (status !== "spinning") {
    const symbol = STATUS_SYMBOLS[status]
    const statusColor =
      status === "success" ? theme.success :
      status === "error" ? theme.error :
      status === "warning" ? theme.warning :
      theme.accent
    return (
      <text>
        <span style={{ fg: statusColor }}>{symbol}</span>
        {text ? <span style={{ fg: theme.foreground }}> {text}</span> : null}
      </text>
    )
  }

  const resolvedColor = color ?? theme.accent
  return (
    <text>
      <span style={{ fg: resolvedColor }}>{frames[frame]}</span>
      {text ? <span style={{ fg: theme.foreground }}> {text}</span> : null}
    </text>
  )
}

import type { ReactNode } from "react"
import { textStyle } from "./text-style"
import { useTheme } from "./theme"

export interface StatusBarItem {
  /** The key or key combination text (e.g., "Tab", "←→", "q"). */
  key: string
  /** Description of what the key does (e.g., "switch focus", "navigate"). */
  label: string
}

export interface StatusBarProps {
  /** Array of keybinding hints to display. */
  items: StatusBarItem[]
  /**
   * Optional content rendered to the left of the keybinding hints.
   * When provided, a dim │ separator appears between it and the hints.
   *
   * **Note:** Since this renders inside a `<text>`, it must be inline content
   * (`<span>` or string). Block-level elements will cause rendering errors.
   */
  extra?: ReactNode
}

export function StatusBar({ items, extra }: StatusBarProps) {
  const theme = useTheme()
  const parts: any[] = []

  if (extra !== undefined) {
    parts.push(
      <span key="extra">{extra}</span>,
    )
    parts.push(
      <span key="pipe" style={textStyle({ dim: true, fg: theme.placeholder })}>{"  \u2502  "}</span>,
    )
  }

  items.forEach((item, i) => {
    if (i > 0) {
      parts.push(<span key={`gap-${i}`}>{" "}</span>)
    }
    parts.push(
      <span key={`key-${i}`} style={textStyle({ bold: true, fg: theme.background, bg: theme.muted })}>
        {` ${item.key} `}
      </span>,
    )
    parts.push(
      <span key={`label-${i}`} style={textStyle({ dim: true, fg: theme.placeholder })}>
        {` ${item.label}`}
      </span>,
    )
  })

  if (parts.length === 0) {
    return null
  }

  return <text>{parts}</text>
}

import { createContext, useContext, useState, Children, isValidElement } from "react"
import type { ReactNode } from "react"
import { textStyle } from "./text-style"
import { useTheme } from "./theme"
import { useKeyboardContext } from "./provider"

// ── Context ──────────────────────────────────────────────────────────────

interface TabsContextValue {
  value: string
  onValueChange: (value: string) => void
}

const TabsContext = createContext<TabsContextValue | null>(null)

function useTabsContext() {
  const ctx = useContext(TabsContext)
  if (!ctx) throw new Error("Tabs compound components must be used within <Tabs>")
  return ctx
}

// ── Tabs (root) ──────────────────────────────────────────────────────────

export interface TabsProps {
  /** The controlled active tab value. */
  value?: string
  /** The default active tab value (uncontrolled). */
  defaultValue?: string
  /** Called when the active tab changes. */
  onValueChange?: (value: string) => void
  children: ReactNode
}

export function Tabs({
  value: controlledValue,
  defaultValue = "",
  onValueChange,
  children,
}: TabsProps) {
  const [internalValue, setInternalValue] = useState(defaultValue)
  const value = controlledValue ?? internalValue
  const handleChange = onValueChange ?? setInternalValue

  return (
    <TabsContext.Provider value={{ value, onValueChange: handleChange }}>
      <box flexDirection="column">{children}</box>
    </TabsContext.Provider>
  )
}

// ── TabsList ─────────────────────────────────────────────────────────────

export interface TabsListProps {
  /** Optional label shown before the tab triggers. */
  label?: string
  /** Whether the tab bar appears focused. */
  focused?: boolean
  /** The foreground color applied to the active trigger. */
  activeColor?: string
  /** Whether to show the horizontal separator below the triggers. */
  separator?: boolean
  /** Keyboard handler — pass useKeyboard from @gridland/utils */
  useKeyboard?: (handler: (event: any) => void) => void
  children: ReactNode
}

export function TabsList({
  label,
  focused = true,
  activeColor,
  separator = true,
  useKeyboard: useKeyboardProp,
  children,
}: TabsListProps) {
  const theme = useTheme()
  const { value, onValueChange } = useTabsContext()
  const useKeyboard = useKeyboardContext(useKeyboardProp)
  const color = activeColor ?? theme.accent

  // Extract trigger values and labels from children
  const triggers: { value: string; label: ReactNode }[] = []
  Children.forEach(children, (child) => {
    if (isValidElement(child) && "value" in child.props) {
      triggers.push({ value: child.props.value as string, label: child.props.children })
    }
  })

  // Keyboard navigation: left/right arrows switch tabs
  useKeyboard?.((event: any) => {
    if (triggers.length === 0) return
    const currentIndex = triggers.findIndex((t) => t.value === value)
    if (event.name === "left" || event.name === "h") {
      const next = currentIndex <= 0 ? triggers.length - 1 : currentIndex - 1
      onValueChange(triggers[next].value)
      event.preventDefault?.()
    } else if (event.name === "right" || event.name === "l") {
      const next = currentIndex >= triggers.length - 1 ? 0 : currentIndex + 1
      onValueChange(triggers[next].value)
      event.preventDefault?.()
    }
  })

  const parts: any[] = []

  if (label !== undefined) {
    parts.push(
      <span
        key="label"
        style={focused ? textStyle({ bold: true, fg: theme.foreground }) : textStyle({ dim: true, fg: theme.muted })}
      >
        {label}{" "}
      </span>,
    )
  }

  triggers.forEach((trigger, i) => {
    const isSelected = trigger.value === value
    const padded = ` ${trigger.label} `

    const style = isSelected
      ? focused
        ? textStyle({ bold: true, fg: theme.background, bg: color })
        : textStyle({ bold: true, fg: theme.background, bg: theme.muted, dim: true })
      : focused
        ? textStyle({ fg: theme.foreground })
        : textStyle({ dim: true, fg: theme.muted })

    if (i > 0) {
      parts.push(
        <span key={`div-${i}`} style={textStyle({ dim: true, fg: theme.muted })}>│</span>,
      )
    }

    parts.push(
      <span key={`opt-${i}`} style={style}>
        {padded}
      </span>,
    )
  })

  return (
    <box flexDirection="column">
      <text>{parts}</text>
      {separator && (
        <text wrapMode="none" style={textStyle({ dim: true, fg: theme.muted })}>
          {"─".repeat(200)}
        </text>
      )}
    </box>
  )
}

// ── TabsTrigger ──────────────────────────────────────────────────────────

export interface TabsTriggerProps {
  /** Unique value that links this trigger to its TabsContent. */
  value: string
  children: ReactNode
}

/**
 * Declares a tab trigger. Does not render anything itself —
 * TabsList reads the value and children props to build the tab bar.
 */
export function TabsTrigger(_props: TabsTriggerProps) {
  return null
}

// ── TabsContent ──────────────────────────────────────────────────────────

export interface TabsContentProps {
  /** The value that must match the active tab for this content to render. */
  value: string
  children: ReactNode
}

export function TabsContent({ value, children }: TabsContentProps) {
  const { value: activeValue } = useTabsContext()
  if (activeValue !== value) return null
  return <>{children}</>
}

// ── Legacy TabBar (simple API) ───────────────────────────────────────────

export interface TabBarProps {
  /** Text label shown before the options. */
  label?: string
  /** Array of option strings to display. */
  options: string[]
  /** Zero-based index of the currently selected option. */
  selectedIndex: number
  /** Whether the tab bar appears focused. */
  focused?: boolean
  /** The foreground color applied to the selected option when focused. */
  activeColor?: string
  /** Whether to show the horizontal separator below tabs. */
  separator?: boolean
  /** Keyboard handler — pass useKeyboard from @gridland/utils */
  useKeyboard?: (handler: (event: any) => void) => void
}

export function TabBar({
  label,
  options,
  selectedIndex,
  focused = true,
  activeColor,
  separator = true,
  useKeyboard,
}: TabBarProps) {
  return (
    <Tabs value={options[selectedIndex]}>
      <TabsList label={label} focused={focused} activeColor={activeColor} separator={separator} useKeyboard={useKeyboard}>
        {options.map((option) => (
          <TabsTrigger key={option} value={option}>
            {option}
          </TabsTrigger>
        ))}
      </TabsList>
    </Tabs>
  )
}

import { createContext, useContext, Children, isValidElement, Fragment } from "react"
import type { ReactNode } from "react"
import { textStyle } from "./text-style"
import { useTheme } from "./theme"

// ── Types ────────────────────────────────────────────────────────────────

type Scalar = string | number | boolean | null | undefined
type ScalarDict = { [key: string]: Scalar }

// ── Context ──────────────────────────────────────────────────────────────

interface TableContextValue {
  columnWidths: number[]
  padding: number
  headerColor: string
  borderColor: string
  foregroundColor: string
}

const TableContext = createContext<TableContextValue | null>(null)

function useTableContext() {
  const ctx = useContext(TableContext)
  if (!ctx) throw new Error("Table compound components must be used within <TableRoot>")
  return ctx
}

// ── Utility functions ────────────────────────────────────────────────────

export function getColumns<T extends ScalarDict>(
  data: T[],
  columnsProp?: (keyof T)[],
): (keyof T)[] {
  if (columnsProp) return columnsProp
  const keys = new Set<keyof T>()
  for (const row of data) {
    for (const key in row) keys.add(key)
  }
  return Array.from(keys)
}

interface ColumnInfo<T> {
  field: keyof T
  width: number
}

export function calculateColumnWidths<T extends ScalarDict>(
  columns: (keyof T)[],
  data: T[],
  padding: number,
): ColumnInfo<T>[] {
  return columns.map((field) => {
    const headerWidth = String(field).length
    const maxDataWidth = data.reduce((max, row) => {
      const val = row[field]
      return Math.max(max, val == null ? 0 : String(val).length)
    }, 0)
    return { field, width: Math.max(headerWidth, maxDataWidth) + padding * 2 }
  })
}

export function padCell(value: string, width: number, padding: number): string {
  const rightPad = width - value.length - padding
  return " ".repeat(padding) + value + " ".repeat(Math.max(0, rightPad))
}

// ── Helpers: extract cell text from React tree ───────────────────────────

function extractCellText(node: ReactNode): string {
  if (node == null) return ""
  if (typeof node === "string") return node
  if (typeof node === "number" || typeof node === "boolean") return String(node)
  if (Array.isArray(node)) return node.map(extractCellText).join("")
  return ""
}

function collectColumnWidths(children: ReactNode, padding: number): number[] {
  const columnMaxWidths: number[] = []

  Children.forEach(children, (section) => {
    if (!isValidElement(section)) return
    if (section.type === TableCaption) return

    Children.forEach(section.props.children, (row: ReactNode) => {
      if (!isValidElement(row)) return

      let colIdx = 0
      Children.forEach(row.props.children, (cell: ReactNode) => {
        if (!isValidElement(cell)) return
        const text = extractCellText(cell.props.children)
        const width = text.length + padding * 2
        if (colIdx >= columnMaxWidths.length) {
          columnMaxWidths.push(width)
        } else {
          columnMaxWidths[colIdx] = Math.max(columnMaxWidths[colIdx], width)
        }
        colIdx++
      })
    })
  })

  return columnMaxWidths
}

function getTotalWidth(columnWidths: number[]): number {
  if (columnWidths.length === 0) return 0
  return columnWidths.reduce((sum, w) => sum + w, 0) + (columnWidths.length - 1)
}

// ── TableRoot (compound root) ────────────────────────────────────────────

export interface TableRootProps {
  children: ReactNode
  padding?: number
  headerColor?: string
  borderColor?: string
}

export function TableRoot({ children, padding = 1, headerColor, borderColor }: TableRootProps) {
  const theme = useTheme()
  const resolvedHeaderColor = headerColor ?? theme.foreground
  const resolvedBorderColor = borderColor ?? theme.muted

  const columnWidths = collectColumnWidths(children, padding)

  return (
    <TableContext.Provider
      value={{
        columnWidths,
        padding,
        headerColor: resolvedHeaderColor,
        borderColor: resolvedBorderColor,
        foregroundColor: theme.foreground,
      }}
    >
      <box>{children}</box>
    </TableContext.Provider>
  )
}

// ── TableHeader ──────────────────────────────────────────────────────────

export interface TableHeaderProps {
  children: ReactNode
}

export function TableHeader({ children }: TableHeaderProps) {
  const ctx = useTableContext()
  const totalWidth = getTotalWidth(ctx.columnWidths)

  return (
    <box>
      {children}
      <text>
        <span style={textStyle({ fg: ctx.borderColor })}>{"\u2500".repeat(totalWidth)}</span>
      </text>
    </box>
  )
}

// ── TableBody ────────────────────────────────────────────────────────────

export interface TableBodyProps {
  children: ReactNode
}

export function TableBody({ children }: TableBodyProps) {
  const ctx = useTableContext()
  const totalWidth = getTotalWidth(ctx.columnWidths)
  const rows = Children.toArray(children)

  return (
    <box>
      {rows.map((row, index) => (
        <Fragment key={index}>
          {row}
          {index < rows.length - 1 && (
            <text>
              <span style={textStyle({ fg: ctx.borderColor, dim: true })}>
                {"\u2500".repeat(totalWidth)}
              </span>
            </text>
          )}
        </Fragment>
      ))}
    </box>
  )
}

// ── TableFooter ──────────────────────────────────────────────────────────

export interface TableFooterProps {
  children: ReactNode
}

export function TableFooter({ children }: TableFooterProps) {
  const ctx = useTableContext()
  const totalWidth = getTotalWidth(ctx.columnWidths)

  return (
    <box>
      <text>
        <span style={textStyle({ fg: ctx.borderColor })}>{"\u2500".repeat(totalWidth)}</span>
      </text>
      {children}
    </box>
  )
}

// ── TableRow ─────────────────────────────────────────────────────────────

export interface TableRowProps {
  children: ReactNode
}

export function TableRow({ children }: TableRowProps) {
  const ctx = useTableContext()
  const parts: any[] = []
  let colIdx = 0

  Children.forEach(children, (child) => {
    if (!isValidElement(child)) return

    const text = extractCellText(child.props.children)
    const width = ctx.columnWidths[colIdx] ?? text.length + ctx.padding * 2
    const padded = padCell(text, width, ctx.padding)
    const isHead = child.type === TableHead

    if (colIdx > 0) {
      parts.push(
        <span key={`sep-${colIdx}`} style={textStyle({ fg: ctx.borderColor, dim: true })}>
          {" "}
        </span>,
      )
    }

    if (isHead) {
      parts.push(
        <span key={`cell-${colIdx}`} style={textStyle({ fg: ctx.headerColor })}>
          {padded}
        </span>,
      )
    } else {
      parts.push(
        <span key={`cell-${colIdx}`} style={textStyle({ fg: ctx.foregroundColor, dim: true })}>
          {padded}
        </span>,
      )
    }

    colIdx++
  })

  return <text>{parts}</text>
}

// ── TableHead ────────────────────────────────────────────────────────────

export interface TableHeadProps {
  children: ReactNode
}

/**
 * Declares a header cell. Does not render itself —
 * TableRow reads the children prop to build the styled row.
 */
export function TableHead(_props: TableHeadProps) {
  return null
}

// ── TableCell ────────────────────────────────────────────────────────────

export interface TableCellProps {
  children: ReactNode
}

/**
 * Declares a body cell. Does not render itself —
 * TableRow reads the children prop to build the styled row.
 */
export function TableCell(_props: TableCellProps) {
  return null
}

// ── TableCaption ─────────────────────────────────────────────────────────

export interface TableCaptionProps {
  children: ReactNode
}

export function TableCaption({ children }: TableCaptionProps) {
  const ctx = useTableContext()
  return (
    <text>
      <span style={textStyle({ fg: ctx.borderColor, dim: true })}>
        {extractCellText(children)}
      </span>
    </text>
  )
}

// ── Table (data-driven convenience wrapper) ────────────────────────

export interface TableProps<T extends ScalarDict> {
  data: T[]
  columns?: (keyof T)[]
  padding?: number
  headerColor?: string
  borderColor?: string
}

export function Table<T extends ScalarDict>({
  data,
  columns: columnsProp,
  padding = 1,
  headerColor,
  borderColor,
}: TableProps<T>) {
  const cols = getColumns(data, columnsProp)

  return (
    <TableRoot padding={padding} headerColor={headerColor} borderColor={borderColor}>
      <TableHeader>
        <TableRow>
          {cols.map((col) => (
            <TableHead key={String(col)}>{String(col)}</TableHead>
          ))}
        </TableRow>
      </TableHeader>
      <TableBody>
        {data.map((row, index) => (
          <TableRow key={index}>
            {cols.map((col) => (
              <TableCell key={String(col)}>
                {row[col] == null ? "" : String(row[col])}
              </TableCell>
            ))}
          </TableRow>
        ))}
      </TableBody>
    </TableRoot>
  )
}

import type { ReactNode } from "react"

export interface TerminalWindowProps {
  /** Content rendered inside the window below the title bar. */
  children: ReactNode
  /** Additional CSS classes applied to the outermost container. */
  className?: string
  /** Text displayed centered in the title bar. */
  title?: string
  /** Minimum width of the window. Applied as inline style. */
  minWidth?: number | string
  /** When true, the window background is transparent. Defaults to false (dark gray). */
  transparent?: boolean
  /** Callback fired when the red (close) button is clicked. */
  onClose?: () => void
  /** Callback fired when the yellow (minimize) button is clicked. */
  onMinimize?: () => void
  /** Callback fired when the green (maximize) button is clicked. */
  onMaximize?: () => void
}

function cn(...classes: (string | undefined | false)[]): string {
  return classes.filter(Boolean).join(" ")
}

export function TerminalWindow({
  children,
  className,
  title,
  minWidth,
  transparent = false,
  onClose,
  onMinimize,
  onMaximize,
}: TerminalWindowProps) {
  return (
    <div
      className={cn(
        "rounded-2xl border shadow-lg overflow-hidden",
        className,
      )}
      style={{
        ...(minWidth != null ? { minWidth } : {}),
        ...(transparent ? {} : { backgroundColor: "#1e1e2e" }),
      }}
    >
      {/* Title Bar */}
      <div
        className="grid grid-cols-3 items-center px-3 py-2.5 border-b"
        style={transparent ? {} : { backgroundColor: "#2a2a3c", borderColor: "#313244" }}
      >
        {/* Traffic Light Buttons */}
        <div className="flex gap-2">
          <button
            onClick={onClose}
            className="w-3 h-3 bg-red-500 hover:bg-red-600 rounded-full transition-colors"
            aria-label="Close"
            type="button"
          />
          <button
            onClick={onMinimize}
            className="w-3 h-3 bg-yellow-500 hover:bg-yellow-600 rounded-full transition-colors"
            aria-label="Minimize"
            type="button"
          />
          <button
            onClick={onMaximize}
            className="w-3 h-3 bg-green-500 hover:bg-green-600 rounded-full transition-colors"
            aria-label="Maximize"
            type="button"
          />
        </div>
        {/* Title */}
        {title && (
          <div
            className="text-center text-sm select-none"
            style={transparent ? {} : { color: "#a6adc8" }}
          >
            {title}
          </div>
        )}
        {/* Empty right column for balance */}
        <div />
      </div>
      {/* Content */}
      <div className="overflow-hidden">{children}</div>
    </div>
  )
}

// @ts-nocheck — OpenTUI intrinsic elements conflict with React's HTML/SVG types
import { useCallback, useRef, useState } from 'react'
import { textStyle } from './text-style'
import { useTheme } from './theme'

export interface TextInputProps {
  /** Field label shown above the input */
  label?: string
  /** Helper text shown inline next to the label */
  description?: string
  /** Error message — overrides description when set */
  error?: string
  /** Whether the field is required (shows indicator on label) */
  required?: boolean
  /** Whether the input is disabled */
  disabled?: boolean
  /** Controlled value */
  value?: string
  /** Called on every keystroke */
  onChange?: (value: string) => void
  /** Called when Enter is pressed */
  onSubmit?: (value: string) => void
  /** Hint text shown when empty */
  placeholder?: string
  /** Prompt string shown before the input (e.g. "> ") */
  prompt?: string
  /** Whether the input is focused and accepting keystrokes */
  focus?: boolean
  /** Maximum characters allowed */
  maxLength?: number
}

export function TextInput({ label, description, error, required = false, disabled = false, value: controlledValue, onChange, onSubmit, placeholder, prompt, focus = false, maxLength }: TextInputProps) {
  const theme = useTheme()
  const [internalValue, setInternalValue] = useState('')
  const isControlled = controlledValue !== undefined
  const controlledRef = useRef(isControlled)
  if (controlledRef.current !== isControlled) {
    console.warn('TextInput: switching between controlled and uncontrolled is not supported.')
    controlledRef.current = isControlled
  }
  const current = isControlled ? controlledValue : internalValue
  const isFocused = focus && !disabled

  const handleInput = useCallback(
    (v: string) => {
      if (!isControlled) setInternalValue(v)
      onChange?.(v)
    },
    [isControlled, onChange],
  )

  const handleSubmit = useCallback(
    (v: string) => {
      onSubmit?.(v)
      if (!isControlled) setInternalValue('')
    },
    [isControlled, onSubmit],
  )

  const empty = !current
  const showLabel = label != null
  const message = error ?? description

  return (
    <box flexDirection="column">
      {showLabel && (
        <text>
          <span style={textStyle({ fg: error ? theme.error : isFocused ? theme.primary : disabled ? theme.muted : theme.foreground, bold: !disabled, dim: disabled })}>
            {isFocused ? '\u25B8 ' : '  '}
            {label}
          </span>
          {required && <span style={textStyle({ fg: theme.error })}>{' *'}</span>}
          {current && maxLength != null && (
            <span style={textStyle({ dim: true, fg: theme.muted })}>
              {' '}
              {current.length}/{maxLength}
            </span>
          )}
          {message != null && (
            <span style={textStyle({ fg: error ? theme.error : theme.muted, dim: !error })}>
              {' | '}
              {message}
            </span>
          )}
        </text>
      )}
      <box flexDirection="row" marginLeft={showLabel ? 2 : 0}>
        {prompt != null && <text style={{ fg: isFocused ? theme.primary : theme.muted }}>{prompt}</text>}
        {isFocused ? (
          <input
            value={current}
            placeholder={placeholder}
            maxLength={maxLength}
            focused
            onInput={handleInput}
            onSubmit={handleSubmit}
            cursorColor={theme.muted}
            cursorStyle={{ style: "line", blinking: empty }}
            placeholderColor={theme.placeholder}
            textColor={theme.foreground}
          />
        ) : (
          <text style={{ fg: empty ? theme.placeholder : disabled ? theme.muted : theme.foreground, dim: disabled }}>{empty ? placeholder : current}</text>
        )}
      </box>
    </box>
  )
}

import { createContext, memo, useContext, useEffect, useMemo, useState } from "react"
import type { ReactNode } from "react"
import { textStyle } from "./text-style"
import { useTheme } from "./theme"
import type { Theme } from "./theme"

// ── Constants ──────────────────────────────────────────────────────

const DOTS = ["○", "◔", "◑", "◕", "●"] as const
const SPINNER_INTERVAL = 150

// ── Step data type (for data-driven usage) ─────────────────────────

export interface Step {
  /** Tool or operation name (e.g. "Think", "Search", "Read"). */
  tool: string
  /** Primary label for the step. */
  label: string
  /** Secondary detail shown dimmed after the label. */
  description?: string
  /** Duration string (e.g. "0.6s", "400ms"). */
  duration?: string
  /** Current status. */
  status: "done" | "running" | "pending" | "error"
  /** Output or detail text shown below the step. */
  output?: string
}

// ── Context ────────────────────────────────────────────────────────

interface ChainOfThoughtContextValue {
  isOpen: boolean
  setIsOpen: (open: boolean) => void
}

const ChainOfThoughtContext = createContext<ChainOfThoughtContextValue | null>(null)

const useChainOfThought = () => {
  const context = useContext(ChainOfThoughtContext)
  if (!context) {
    throw new Error("ChainOfThought components must be used within <ChainOfThought>")
  }
  return context
}

// ── Status helper ──────────────────────────────────────────────────

function getStepColor(status: string, theme: Theme): string {
  switch (status) {
    case "done": return theme.success
    case "running": return theme.primary
    case "pending": return theme.muted
    case "error": return theme.error
    default: return theme.muted
  }
}

// ── ChainOfThought (root) ──────────────────────────────────────────

export interface ChainOfThoughtProps {
  /** Controlled open state. */
  open?: boolean
  /** Default open state (uncontrolled). Defaults to false. */
  defaultOpen?: boolean
  /** Called when the open state changes. */
  onOpenChange?: (open: boolean) => void
  children: ReactNode
}

export const ChainOfThought = memo(({
  open,
  defaultOpen = false,
  onOpenChange,
  children,
}: ChainOfThoughtProps) => {
  const [internalOpen, setInternalOpen] = useState(defaultOpen)
  const isOpen = open ?? internalOpen
  const setIsOpen = onOpenChange ?? setInternalOpen

  const context = useMemo(
    () => ({ isOpen, setIsOpen }),
    [isOpen, setIsOpen],
  )

  return (
    <ChainOfThoughtContext.Provider value={context}>
      <box flexDirection="column">
        {children}
      </box>
    </ChainOfThoughtContext.Provider>
  )
})

// ── ChainOfThoughtHeader ───────────────────────────────────────────

export interface ChainOfThoughtHeaderProps {
  /** Duration string shown after the label (e.g. "3.2s"). */
  duration?: string
  /** Header label content. Defaults to "Thought for". */
  children?: ReactNode
}

export const ChainOfThoughtHeader = memo(({
  duration,
  children = "Thought for",
}: ChainOfThoughtHeaderProps) => {
  const theme = useTheme()
  const { isOpen } = useChainOfThought()
  const arrow = isOpen ? "▼" : "▶"

  return (
    <text>
      <span style={textStyle({ fg: theme.muted })}>{arrow}</span>
      <span style={textStyle({ dim: true, fg: theme.muted })}>{" "}{children}{duration ? " " + duration : ""}</span>
    </text>
  )
})

// ── ChainOfThoughtContent ──────────────────────────────────────────

export interface ChainOfThoughtContentProps {
  children: ReactNode
}

export const ChainOfThoughtContent = memo(({ children }: ChainOfThoughtContentProps) => {
  const { isOpen } = useChainOfThought()
  if (!isOpen) return null
  return <>{children}</>
})

// ── ChainOfThoughtStep ─────────────────────────────────────────────

export interface ChainOfThoughtStepProps {
  /** Primary label for the step. */
  label: string
  /** Secondary detail shown dimmed after the label. */
  description?: string
  /** Current status. Defaults to "done". */
  status?: "done" | "running" | "pending" | "error"
  /** Set to true to hide the vertical pipe connector below. */
  isLast?: boolean
  /** Output content rendered below the step with a pipe gutter. */
  children?: ReactNode
}

export const ChainOfThoughtStep = memo(({
  label,
  description,
  status = "done",
  isLast = false,
  children,
}: ChainOfThoughtStepProps) => {
  const theme = useTheme()
  const isActive = status === "running"
  const isPending = status === "pending"
  const color = getStepColor(status, theme)
  const pipe = "│"

  // Self-contained spinner animation — only ticks when this step is active
  const [frame, setFrame] = useState(0)
  useEffect(() => {
    if (!isActive) { setFrame(0); return }
    const id = setInterval(() => setFrame(f => f + 1), SPINNER_INTERVAL)
    return () => clearInterval(id)
  }, [isActive])

  const dot = isActive
    ? DOTS[frame % DOTS.length]!
    : isPending ? "○" : "●"

  return (
    <box flexDirection="column" marginLeft={1}>
      <text>
        <span style={textStyle({ fg: color })}>{dot}</span>
        <span style={textStyle({ fg: theme.foreground })}>{" "}</span>
        <span style={textStyle({ fg: isPending ? theme.muted : color, dim: isPending, bold: isActive })}>{label}</span>
        {description && <span style={textStyle({ dim: true, fg: theme.muted })}>{" — " + description}</span>}
      </text>
      {children && (
        <text>
          <span style={textStyle({ fg: color, dim: true })}>{pipe + "  "}</span>
          <span style={textStyle({ fg: status === "error" ? theme.error : theme.accent })}>{children}</span>
        </text>
      )}
      {!isLast && (
        <text>
          <span style={textStyle({ fg: color, dim: true })}>{pipe}</span>
        </text>
      )}
    </box>
  )
})

// ── Display names ──────────────────────────────────────────────────

ChainOfThought.displayName = "ChainOfThought"
ChainOfThoughtHeader.displayName = "ChainOfThoughtHeader"
ChainOfThoughtContent.displayName = "ChainOfThoughtContent"
ChainOfThoughtStep.displayName = "ChainOfThoughtStep"

// @ts-nocheck — OpenTUI intrinsic elements conflict with React's HTML/SVG types
import { useState, useRef, useCallback, useEffect, type ReactNode } from "react"
import {
  useFocus,
  FocusProvider,
  FocusScope,
  useKeyboard,
  useShortcuts,
  useFocusedShortcuts,
} from "@gridland/utils"
import { StatusBar } from "./status-bar"
import { textStyle } from "./text-style"

// ── Types ─────────────────────────────────────────────────────────────

export interface SideNavItem {
  /** Unique identifier for this nav item. */
  id: string
  /** Display label shown in the sidebar. */
  name: string
}

export interface SideNavProps {
  /** List of navigable items. */
  items: SideNavItem[]
  /** Width of the sidebar in columns. @default 20 */
  sidebarWidth?: number
  /** Optional title displayed above the sidebar. */
  title?: string
  /**
   * Render the main panel content for the active item.
   * Receives the active item, whether the user has selected it for interaction,
   * and a captureKeyboard callback for routing keyboard events.
   */
  children: (ctx: {
    activeItem: SideNavItem
    isInteracting: boolean
    captureKeyboard: (handler: (event: any) => void) => void
  }) => ReactNode
  /** Color for the focused sidebar item text. @default "#cdd6f4" */
  focusedColor?: string
  /** Color for the selected (interacting) sidebar item text. @default "#a5b4fc" */
  selectedColor?: string
  /** Color for unfocused sidebar item text. @default "#6c7086" */
  mutedColor?: string
  /** Background highlight color for focused sidebar item. @default "#313244" */
  highlightBg?: string
  /** Border color for the main panel. @default "#3b3466" */
  borderColor?: string
  /** Border color for the main panel when interacting. @default "#818cf8" */
  activeBorderColor?: string
  /** Show the status bar at the bottom. @default true */
  showStatusBar?: boolean
  /**
   * Programmatically switch the active item by ID. When this changes to a new
   * value that matches an item in the list, the nav switches to that item.
   * User navigation via arrow keys always overrides this after it fires.
   */
  requestedActiveId?: string
}

// ── NavItem ───────────────────────────────────────────────────────────

function NavItemRow({ item, autoFocus, onFocus, onSelectChange, handlerRef, focusedColor, selectedColor, mutedColor, highlightBg }: {
  item: SideNavItem
  autoFocus?: boolean
  onFocus: () => void
  onSelectChange: (selected: boolean) => void
  handlerRef: React.MutableRefObject<((event: any) => void) | null>
  focusedColor: string
  selectedColor: string
  mutedColor: string
  highlightBg: string
}) {
  const { isFocused, isSelected, isAnySelected, focusId, focusRef } = useFocus({ id: item.id, autoFocus })

  useEffect(() => {
    if (isFocused) onFocus()
  }, [isFocused])

  useEffect(() => {
    onSelectChange(isSelected)
  }, [isSelected])

  useKeyboard((event) => {
    handlerRef.current?.(event)
  }, { focusId, selectedOnly: true })

  useShortcuts(
    isSelected
      ? [{ key: "esc", label: "back" }]
      : [{ key: "↑↓", label: "navigate" }, { key: "enter", label: "select" }],
    focusId,
  )

  const fg = isSelected ? selectedColor
    : isFocused ? focusedColor
    : mutedColor
  const bg = isFocused && !isSelected && !isAnySelected ? highlightBg : undefined

  return (
    <box ref={focusRef} height={1} paddingX={1}>
      <text style={textStyle({ fg, bg, bold: isFocused || isSelected })}>
        {isFocused || isSelected ? ">" : " "} {item.name}
      </text>
    </box>
  )
}

// ── SideNavStatusBar ──────────────────────────────────────────────────

function SideNavStatusBar() {
  const shortcuts = useFocusedShortcuts()
  return (
    <box paddingX={1} paddingBottom={1}>
      <StatusBar items={shortcuts} />
    </box>
  )
}

// ── SideNav ───────────────────────────────────────────────────────────

export function SideNav({
  items,
  sidebarWidth = 20,
  title,
  children,
  focusedColor = "#cdd6f4",
  selectedColor = "#a5b4fc",
  mutedColor = "#6c7086",
  highlightBg = "#313244",
  borderColor = "#3b3466",
  activeBorderColor = "#818cf8",
  showStatusBar = true,
  requestedActiveId,
}: SideNavProps) {
  const [activeIndex, setActiveIndex] = useState(0)
  const [isInteracting, setIsInteracting] = useState(false)
  const handlerRef = useRef<((event: any) => void) | null>(null)
  const lastRequestedActiveIdRef = useRef<string | undefined>()
  // Tracks which nav item triggered the interaction, decoupled from activeIndex.
  // Without this, changing activeIndex programmatically breaks the isInteracting
  // update when that original item deselects (e.g. on Esc).
  const interactingItemIdRef = useRef<string | null>(null)

  // Switch active item when requestedActiveId changes to a new value.
  // Uses a ref to avoid re-processing the same ID if items re-render.
  useEffect(() => {
    if (!requestedActiveId || requestedActiveId === lastRequestedActiveIdRef.current) return
    lastRequestedActiveIdRef.current = requestedActiveId
    const idx = items.findIndex(item => item.id === requestedActiveId)
    if (idx !== -1) setActiveIndex(idx)
  }, [requestedActiveId, items])

  const captureKeyboard = useCallback((handler: (event: any) => void) => {
    handlerRef.current = handler
  }, [])

  const activeItem = items[activeIndex]

  return (
    <FocusProvider selectable>
      <box flexDirection="column" flexGrow={1}>
        {title && (
          <box paddingX={2} paddingTop={1}>
            <text style={textStyle({ bold: true, fg: focusedColor })}>
              {title}
            </text>
          </box>
        )}

        <box flexDirection="row" flexGrow={1} paddingTop={1}>
          {/* Sidebar */}
          <box flexDirection="column" width={sidebarWidth} paddingTop={1}>
            {items.map((item, i) => (
              <NavItemRow
                key={item.id}
                item={item}
                autoFocus={i === 0}
                onFocus={() => setActiveIndex(i)}
                onSelectChange={(selected) => {
                  if (selected) {
                    interactingItemIdRef.current = item.id
                    setIsInteracting(true)
                  } else if (interactingItemIdRef.current === item.id) {
                    interactingItemIdRef.current = null
                    setIsInteracting(false)
                  }
                }}
                handlerRef={handlerRef}
                focusedColor={focusedColor}
                selectedColor={selectedColor}
                mutedColor={mutedColor}
                highlightBg={highlightBg}
              />
            ))}
          </box>

          {/* Main panel */}
          <box flexDirection="column" flexGrow={1} paddingRight={1}>
            <box
              flexDirection="column"
              flexGrow={1}
              border
              borderStyle={"rounded" as const}
              borderColor={isInteracting ? activeBorderColor : borderColor}
            >
              <box paddingX={1}>
                <text style={textStyle({ bold: true, fg: selectedColor })}>
                  {activeItem.name}
                </text>
                {isInteracting && (
                  <text style={textStyle({ dim: true, fg: mutedColor })}> (interactive)</text>
                )}
              </box>
              {isInteracting ? (
                <FocusScope trap selectable autoFocus autoSelect restoreOnUnmount>
                  {children({ activeItem, isInteracting, captureKeyboard })}
                </FocusScope>
              ) : (
                children({ activeItem, isInteracting, captureKeyboard })
              )}
            </box>
          </box>
        </box>

        {showStatusBar && <SideNavStatusBar />}
      </box>
    </FocusProvider>
  )
}
